// CITY ROTATION — muda automaticamente a cada semana
const cities = [
  { cities: ['São Paulo'], country: 'BR', locationQuery: 'São Paulo, SP, Brasil', maxPerSearch: 15 },
  { cities: ['Rio de Janeiro', 'Belo Horizonte'], country: 'BR', locationQuery: 'Rio de Janeiro, RJ, Brasil', maxPerSearch: 8 },
  { cities: ['Lisboa', 'Porto'], country: 'PT', locationQuery: 'Lisboa, Portugal', maxPerSearch: 8 },
  { cities: ['Curitiba', 'Florianópolis', 'Porto Alegre'], country: 'BR', locationQuery: 'Curitiba, PR, Brasil', maxPerSearch: 5 },
  { cities: ['Brasília', 'Goiânia'], country: 'BR', locationQuery: 'Brasília, DF, Brasil', maxPerSearch: 8 },
  { cities: ['Salvador', 'Recife'], country: 'BR', locationQuery: 'Salvador, BA, Brasil', maxPerSearch: 8 },
  { cities: ['Braga', 'Faro', 'Coimbra', 'Aveiro'], country: 'PT', locationQuery: 'Braga, Portugal', maxPerSearch: 4 },
  { cities: ['São Paulo'], country: 'BR', locationQuery: 'São Paulo, SP, Brasil', maxPerSearch: 15 }
];

const now = new Date();
const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNumber = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const weekLabel = `W${weekNumber}-${now.getFullYear()}`;
const cityIndex = (weekNumber - 1) % cities.length;
const config = cities[cityIndex];

const searchTerms = [
  'clínica estética',
  'clínica de emagrecimento',
  'dermatologista',
  'harmonização facial'
];

return [{
  json: {
    weekLabel,
    weekNumber,
    cityIndex,
    cities: config.cities,
    country: config.country,
    locationQuery: config.locationQuery,
    maxPerSearch: config.maxPerSearch,
    searchTerms,
    runDate: now.toISOString()
  }
}];

// PRE-FILTER + NORMALIZE
// Remove: <5 reviews, <3 stars, closed, irrelevant categories
const input = $input.all();
const cityConfig = $('City Rotation').first().json;
const seen = new Set();
const results = [];

const irrelevantCategories = [
  'farmácia', 'pharmacy', 'laboratório', 'laboratory',
  'hospital público', 'public hospital', 'dentist',
  'veterinário', 'veterinary', 'fisioterapia'
];

for (const item of input) {
  const d = item.json;

  // Skip permanently closed
  if (d.permanentlyClosed) continue;
  if (d.temporarilyClosed) continue;

  // Skip <5 reviews
  const reviewCount = d.reviewsCount || (d.reviews ? d.reviews.length : 0) || 0;
  if (reviewCount < 5) continue;

  // Skip <3 stars
  const rating = d.totalScore || d.stars || d.rating || 0;
  if (rating < 3) continue;

  // Skip irrelevant categories
  const cats = (d.categories || []).map(c => (c || '').toLowerCase()).join(' ');
  const category = (d.categoryName || d.category || '').toLowerCase();
  const allCats = cats + ' ' + category;
  const isIrrelevant = irrelevantCategories.some(ic => allCats.includes(ic));
  if (isIrrelevant) continue;

  // Deduplicate by Google Maps URL
  const gmapsUrl = d.url || d.placeUrl || '';
  if (seen.has(gmapsUrl)) continue;
  seen.add(gmapsUrl);

  // Check if owner responds to reviews
  let respondsToReviews = false;
  let responseCount = 0;
  if (d.reviews && Array.isArray(d.reviews)) {
    for (const r of d.reviews) {
      if (r.responseFromOwnerText || r.ownerResponse) responseCount++;
    }
    respondsToReviews = responseCount > 0;
  }

  results.push({
    json: {
      nome: d.title || d.name || '',
      categoria: d.categoryName || d.category || '',
      cidade: cityConfig.cities[0],
      pais: cityConfig.country,
      telefone: d.phone || '',
      website: d.website || d.url || '',
      gmapsUrl: gmapsUrl,
      rating: rating,
      reviewsCount: reviewCount,
      respondsToReviews: respondsToReviews,
      reviewResponseRate: d.reviews ? `${responseCount}/${d.reviews.length}` : '0/0',
      ownerPhotosCount: (d.imageCategories || []).length,
      hasWebsite: !!(d.website),
      openingHours: d.openingHours || null,
      categories: d.categories || [],
      description: d.description || '',
      weekLabel: cityConfig.weekLabel,
      runDate: cityConfig.runDate
    }
  });
}

return results;

// PARSE CLAUDE RESPONSE + MERGE WITH ORIGINAL LEADS
const claudeResponse = $json;
const allLeads = $('Prepare Claude Payload').first().json.allLeads;
const weekLabel = allLeads[0]?.weekLabel || '';
const runDate = allLeads[0]?.runDate || new Date().toISOString();

let scores;
try {
  // Claude Bridge returns {output: "..."} or {result: "..."}
  const raw = claudeResponse.output || claudeResponse.result || claudeResponse.body || JSON.stringify(claudeResponse);
  // Extract JSON array from response
  const jsonMatch = raw.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    scores = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON array found in Claude response');
  }
} catch (e) {
  // Fallback: return leads without AI scoring
  return allLeads.map((lead, i) => ({
    json: {
      ...lead,
      score: 50,
      classe: 'B',
      perfil: 'balanced',
      servicoPrimario: 'Diagnóstico Digital',
      servicoSecundario: 'Pacote Completo',
      anguloAbordagem: 'Claude scoring failed — revisar manualmente',
      claudeError: e.message
    }
  }));
}

// Merge scores with lead data
const results = [];
for (let i = 0; i < allLeads.length; i++) {
  const lead = allLeads[i];
  const scoreData = scores.find(s => s.index === i) || scores[i] || {};

  // Merge gaps from website scan + Claude
  const allGaps = [...new Set([...(lead.gapsDetected || []), ...(scoreData.gapsDetected || [])])];
  if (!lead.hasWebsite) allGaps.push('sem_site');
  if (lead.respondsToReviews === false) allGaps.push('nao_responde_reviews');

  results.push({
    json: {
      nome: lead.nome,
      categoria: lead.categoria,
      cidade: lead.cidade,
      pais: lead.pais,
      telefone: lead.telefone,
      website: lead.hasWebsite ? lead.website : '',
      gmapsUrl: lead.gmapsUrl,
      rating: lead.rating,
      reviewsCount: lead.reviewsCount,
      score: scoreData.score || 50,
      classe: scoreData.classe || 'B',
      perfil: scoreData.perfil || 'balanced',
      servicoPrimario: scoreData.servicoPrimario || '',
      servicoSecundario: scoreData.servicoSecundario || '',
      anguloAbordagem: scoreData.anguloAbordagem || '',
      gapsDetected: allGaps,
      tagsTech: lead.tagsTech || [],
      fazTrafegoPago: lead.fazTrafegoPago || false,
      respondsToReviews: lead.respondsToReviews || false,
      temAgendamento: lead.temAgendamento || false,
      status: 'Novo',
      source: 'Google Maps',
      weekLabel: weekLabel,
      runDate: runDate
    }
  });
}

return results;

const allLeads = $('Parse Claude + Merge').all().map(i => i.json);

const scoreA = allLeads.filter(l => l.classe === 'A');
const scoreB = allLeads.filter(l => l.classe === 'B');
const scoreC = allLeads.filter(l => l.classe === 'C');
const heavyUsers = allLeads.filter(l => l.perfil === 'heavy_user');

const topLeads = scoreA
  .sort((a, b) => (b.score || 0) - (a.score || 0))
  .slice(0, 3)
  .map(l => `  • ${l.nome} (${l.score}) — ${l.servicoPrimario}`)
  .join('\n');

const weekLabel = allLeads[0]?.weekLabel || 'W??';
const cidade = allLeads[0]?.cidade || '??';

const message = `🎯 Lead Gen TM — ${weekLabel} (${cidade})\n\nTotal scrapeado: ${allLeads.length}\nScore A: ${scoreA.length} | Score B: ${scoreB.length} | Score C: ${scoreC.length}\nHeavy Users: ${heavyUsers.length}\n\n🏆 Top 3:\n${topLeads || '  Nenhum Score A esta semana'}\n\n📊 Airtable: https://airtable.com/appHlW68vIgSzS8BX/tblJfhyu63msByds6`;

return [{ json: { message, scoreA: scoreA.length, scoreB: scoreB.length, scoreC: scoreC.length, total: allLeads.length } }];

const message = $('Aggregate Stats').first().json.message;

let text = message
  .replace(/\*\*(.*?)\*\*/g, '*$1*')
  .replace(/^- /gm, '• ')
  .replace(/---/g, '───');

if (text.length > 4000) {
  text = text.substring(0, 3950) + '\n\n(truncado)';
}

return [{ json: { text, number: '351913095597' } }];

const items = $input.all();
const urlsToScan = [];
const noWebsiteLeads = [];

for (const item of items) {
  const lead = item.json;
  const url = lead.website || '';

  if (!lead.hasWebsite || !url || url.includes('google.com/maps') || url.includes('instagram.com')) {
    noWebsiteLeads.push({
      ...lead,
      tagsTech: [],
      gapsDetected: ['sem_site','sem_analytics','sem_pixel','sem_google_ads','sem_blog','sem_seo','sem_schema','sem_whatsapp_widget','sem_agendamento'],
      fazTrafegoPago: false,
      temAgendamento: false,
      websiteScanned: false
    });
  } else {
    urlsToScan.push({ url: url, userData: { leadIndex: urlsToScan.length, nome: lead.nome } });
  }
}

return [{
  json: {
    urlsToScan,
    noWebsiteLeads,
    allLeads: items.map(i => i.json),
    hasUrlsToScan: urlsToScan.length > 0
  }
}];
